112→function normalizeCategory(input: string | undefined): SubmissionCategory | null {
113→  if (!input) return null;
114→  const raw = input.trim();
115→  if (raw === "FUEL") return "fuel_station";
116→  if (raw === "MOBILE_MONEY" || raw === "KIOSK") return "mobile_money";
117→  if (raw === "PHARMACY") return "pharmacy";
118→  if (raw === "fuel_station" || raw === "mobile_money" || raw === "pharmacy") return raw;
119→  return null;
120→}
