152→function mimeToExtension(mime: string): string {
153→  switch (mime) {
154→    case "image/png":
155→      return "png";
156→    case "image/webp":
157→      return "webp";
158→    case "image/heic":
159→      return "heic";
160→    case "image/heif":
161→      return "heif";
162→    default:
163→      return "jpg";
164→  }
165→}
