167→function parseImagePayload(imageBase64: string): { imageBuffer: Buffer; mime: string; ext: string } | null {
168→  const match = imageBase64.match(INLINE_IMAGE_REGEX);
169→  if (!match) return null;
170→
171→  const mime = match[1]?.toLowerCase() ?? "";
172→  if (!allowedImageMime.has(mime)) return null;
173→
174→  const base64 = stripBase64Prefix(imageBase64);
175→  const imageBuffer = Buffer.from(base64, "base64");
176→  if (!imageBuffer.length) return null;
177→
178→  return { imageBuffer, mime, ext: mimeToExtension(mime) };
179→}
