198→function normalizeIp(raw: string | null): string | null {
199→  if (!raw) return null;
200→  const first = raw.split(",")[0]?.trim();
201→  if (!first) return null;
202→  const cleaned = first.replace(/^\[|\]$/g, "");
203→  if (cleaned.startsWith("::ffff:")) return cleaned.slice(7);
204→  if (/^\d+\.\d+\.\d+\.\d+:\d+$/.test(cleaned)) return cleaned.split(":")[0] ?? null;
205→  return cleaned;
206→}
207→
208→function isPrivateIp(ip: string): boolean {
209→  if (ip === "127.0.0.1" || ip === "::1") return true;
210→  if (ip.startsWith("10.")) return true;
211→  if (ip.startsWith("192.168.")) return true;
212→  if (ip.startsWith("172.")) {
213→    const second = Number(ip.split(".")[1]);
214→    if (second >= 16 && second <= 31) return true;
215→  }
216→  if (ip.startsWith("fc") || ip.startsWith("fd")) return true;
217→  if (ip.startsWith("fe80:")) return true;
218→  return false;
219→}
