254→function validateCreatePayload(category: SubmissionCategory, details: SubmissionDetails): string | null {
255→  const missing = listCreateMissingFields(category, details);
256→  if (missing.length > 0) return `Missing required fields: ${missing.join(", ")}`;
257→  return null;
