260→function getUserDisplayName(userId: string, name: string | null, email: string | null): string {
261→  if (name && name.trim()) return name.trim();
262→  if (email) {
263→    const atIndex = email.indexOf("@");
264→    if (atIndex > 0) return email.slice(0, atIndex);
265→    return email;
266→  }
267→  return userId || "Contributor";
