275→function getSecondaryPhotoUrl(event: PointEvent): string | null {
276→  const details = event.details as Record<string, unknown> | undefined;
277→  const secondPhotoUrl = details?.secondPhotoUrl;
278→  if (typeof secondPhotoUrl !== "string") return null;
279→  const normalized = secondPhotoUrl.trim();
280→  return normalized || null;
281→}
