348→async function buildAdminSubmissionEvents(events: PointEvent[]): Promise<AdminSubmissionEvent[]> {
349→  const sortedEvents = [...events].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
350→  const userIds = Array.from(
351→    new Set(
352→      sortedEvents
353→        .map((event) => normalizeActorId(event.userId))
354→        .filter((value) => value.length > 0),
355→    ),
356→  );
357→
358→  const profileEntries = await Promise.all(
359→    userIds.map(async (userId) => [userId, await getUserProfile(userId)] as const),
360→  );
361→  const profileByUserId = new Map(profileEntries);
362→  const output: AdminSubmissionEvent[] = [];
363→  let fallbackLookups = 0;
364→
365→  for (const event of sortedEvents) {
366→    const normalizedUserId = normalizeActorId(event.userId);
367→    const profile = profileByUserId.get(normalizedUserId) ?? null;
368→    const emailFromProfile = typeof profile?.email === "string" ? profile.email.trim().toLowerCase() : "";
369→    const email = emailFromProfile || (normalizedUserId.includes("@") ? normalizedUserId : null);
370→    const name = getUserDisplayName(normalizedUserId, profile?.name ?? null, email);
371→    let fraudCheck = getEventFraudCheck(event);
372→    if (shouldRunFallbackFraudCheck(event, fraudCheck) && fallbackLookups < MAX_FORENSICS_FALLBACK_LOOKUPS) {
373→      fallbackLookups += 1;
374→      try {
375→        fraudCheck = await buildFallbackFraudCheck(event, fraudCheck);
376→      } catch {
377→        fraudCheck = fraudCheck ?? null;
378→      }
379→    }
380→
381→    output.push({
382→      event,
383→      user: {
384→        id: normalizedUserId || event.userId,
385→        name,
386→        email,
387→      },
388→      fraudCheck,
389→    });
390→  }
391→
392→  return output;
393→}
