187→interface GroupedPoint {
188→  pointId: string;
189→  events: AdminSubmissionEvent[];
190→  category: AdminSubmissionEvent['event']['category'];
191→  siteName: string;
192→  latestEvent: AdminSubmissionEvent;
193→  createdEvent: AdminSubmissionEvent | null;
194→  enrichEvents: AdminSubmissionEvent[];
195→  allPhotos: { url: string; eventType: string; createdAt: string; metadata: SubmissionPhotoMetadata | null }[];
196→}
197→
198→function groupEventsByPoint(items: AdminSubmissionEvent[], language: 'en' | 'fr'): GroupedPoint[] {
199→  const groups = new Map<string, AdminSubmissionEvent[]>();
200→  for (const item of items) {
201→    const pid = item.event.pointId;
202→    const existing = groups.get(pid);
203→    if (existing) {
204→      existing.push(item);
205→    } else {
206→      groups.set(pid, [item]);
207→    }
208→  }
209→  const result: GroupedPoint[] = [];
210→  for (const [pointId, events] of groups) {
211→    const sorted = [...events].sort((a, b) => new Date(a.event.createdAt).getTime() - new Date(b.event.createdAt).getTime());
212→    const latestEvent = sorted[sorted.length - 1]!;
213→    const createdEvent = sorted.find((e) => e.event.eventType === 'CREATE_EVENT') ?? null;
214→    const enrichEvents = sorted.filter((e) => e.event.eventType === 'ENRICH_EVENT');
215→    const allPhotos: GroupedPoint['allPhotos'] = [];
216→    for (const ev of sorted) {
217→      const photoUrl = ev.event.photoUrl;
218→      if (photoUrl && typeof photoUrl === 'string' && photoUrl.trim()) {
219→        allPhotos.push({
220→          url: photoUrl,
221→          eventType: ev.event.eventType,
222→          createdAt: ev.event.createdAt,
223→          metadata: ev.fraudCheck?.primaryPhoto ?? null,
224→        });
225→      }
226→      const details = ev.event.details as SubmissionDetails;
227→      const secondUrl = typeof details.secondPhotoUrl === 'string' && details.secondPhotoUrl.trim() ? details.secondPhotoUrl : null;
228→      if (secondUrl) {
229→        allPhotos.push({
230→          url: secondUrl,
231→          eventType: ev.event.eventType + ' (secondary)',
232→          createdAt: ev.event.createdAt,
233→          metadata: ev.fraudCheck?.secondaryPhoto ?? null,
234→        });
235→      }
236→    }
237→    result.push({
238→      pointId,
239→      events: sorted,
240→      category: latestEvent.event.category,
241→      siteName: getSiteName(createdEvent ?? latestEvent, language),
242→      latestEvent,
243→      createdEvent,
244→      enrichEvents,
245→      allPhotos,
246→    });
247→  }
248→  return result.sort((a, b) => new Date(b.latestEvent.event.createdAt).getTime() - new Date(a.latestEvent.event.createdAt).getTime());
249→}
