 31→function deterministicUuid(seed: string): string {
 32→  const hex = createHash("sha1").update(seed).digest("hex").slice(0, 32).split("");
 33→  hex[12] = "5";
 34→  const variant = parseInt(hex[16], 16);
 35→  hex[16] = ((variant & 0x3) | 0x8).toString(16);
 36→  return `${hex.slice(0, 8).join("")}-${hex.slice(8, 12).join("")}-${hex.slice(12, 16).join("")}-${hex.slice(16, 20).join("")}-${hex.slice(20, 32).join("")}`;
 37→}
