 31→const createMarkerIcon = (color: string) =>
 32→  L.divIcon({
 33→    className: '',
 34→    html: `<div style="width:26px;height:26px;border-radius:9999px;background:${color};border:2px solid #ffffff;box-shadow:0 8px 16px rgba(15,43,70,0.35);display:flex;align-items:center;justify-content:center;"></div>`,
 35→    iconSize: [26, 26],
 36→    iconAnchor: [13, 13]
 37→  });
