 39→const clusterIconCache = new Map<string, L.DivIcon>();
 40→
 41→const getClusterIcon = (color: string, count: number) => {
 42→  const key = `${color}_${count}`;
 43→  const cached = clusterIconCache.get(key);
 44→  if (cached) return cached;
 45→  const icon = L.divIcon({
 46→    className: '',
 47→    html: `<div style="min-width:28px;height:28px;padding:0 8px;border-radius:9999px;background:${color};border:2px solid #ffffff;box-shadow:0 8px 16px rgba(15,43,70,0.35);display:flex;align-items:center;justify-content:center;color:#ffffff;font-size:11px;font-weight:700;line-height:1;">${count}</div>`,
 48→    iconSize: [28, 28],
 49→    iconAnchor: [14, 14]
 50→  });
 51→  clusterIconCache.set(key, icon);
 52→  return icon;
 53→};
