 59→const MapSizeSync: React.FC<{ active: boolean }> = ({ active }) => {
 60→  const map = useMap();
 61→
 62→  useEffect(() => {
 63→    if (!active) return;
 64→    const rafId = requestAnimationFrame(() => {
 65→      map.invalidateSize({ animate: false });
 66→    });
 67→    const timeoutId = window.setTimeout(() => {
 68→      map.invalidateSize({ animate: false });
 69→    }, 140);
 70→
 71→    return () => {
 72→      cancelAnimationFrame(rafId);
 73→      window.clearTimeout(timeoutId);
 74→    };
 75→  }, [active, map]);
 76→
 77→  return null;
 78→};
